HYPOTHESIS_000016_AUTOGLUON_001_PY_B59B1C04C4_SOURCE = 'import numpy as np\nimport pandas as pd\n\n\nNUMERIC_COLUMNS = (\n    "sleep_duration",\n    "heart_rate",\n    "bmi",\n    "calorie_expenditure",\n    "step_count",\n    "exercise_duration",\n    "water_intake",\n)\n\nTRAIN_ID_MAX = 690087\nEPSILON = 1e-6\n\n\ndef _as_numeric_series(raw, column):\n    if column in raw.columns:\n        return pd.to_numeric(raw[column], errors="coerce")\n    return pd.Series(np.nan, index=raw.index, dtype="float64")\n\n\ndef _is_multiple(series, step):\n    values = series.to_numpy(dtype="float64", copy=False)\n    out = np.zeros(len(series), dtype=bool)\n    mask = np.isfinite(values)\n    if mask.any():\n        ratio = values[mask] / step\n        out[mask] = np.abs(ratio - np.round(ratio)) <= EPSILON\n    return pd.Series(out, index=series.index)\n\n\ndef _decimal_tiers(series):\n    values = series.to_numpy(dtype="float64", copy=False)\n    finite = np.isfinite(values)\n\n    integer_like = np.zeros(len(series), dtype=bool)\n    one_decimal_like = np.zeros(len(series), dtype=bool)\n    two_decimal_like = np.zeros(len(series), dtype=bool)\n\n    if finite.any():\n        finite_values = values[finite]\n        integer_like[finite] = np.abs(finite_values - np.round(finite_values)) <= EPSILON\n        one_decimal_like[finite] = np.abs(finite_values * 10.0 - np.round(finite_values * 10.0)) <= EPSILON\n        two_decimal_like[finite] = np.abs(finite_values * 100.0 - np.round(finite_values * 100.0)) <= EPSILON\n\n    integer_tier = integer_like\n    one_decimal_tier = one_decimal_like & ~integer_like\n    two_decimal_tier = two_decimal_like & ~one_decimal_like\n    finer_tier = finite & ~two_decimal_like\n\n    return integer_tier, one_decimal_tier, two_decimal_tier, finer_tier, finite\n\n\ndef _training_mask(raw):\n    if "id" not in raw.columns:\n        return pd.Series(True, index=raw.index)\n\n    ids = pd.to_numeric(raw["id"], errors="coerce")\n    mask = ids <= TRAIN_ID_MAX\n    if mask.any():\n        return mask.fillna(False)\n    return pd.Series(True, index=raw.index)\n\n\ndef _safe_fraction(numerator, denominator):\n    return np.divide(\n        numerator,\n        denominator,\n        out=np.zeros_like(numerator, dtype="float64"),\n        where=denominator > 0,\n    )\n\n\ndef add_report_granularity_clipping_signature(raw, deps, aux):\n    features = pd.DataFrame(index=raw.index)\n    train_mask = _training_mask(raw)\n\n    observed_count = np.zeros(len(raw), dtype="float64")\n    coarse_count = np.zeros(len(raw), dtype="float64")\n    integer_count = np.zeros(len(raw), dtype="float64")\n    tenth_count = np.zeros(len(raw), dtype="float64")\n    hundredth_count = np.zeros(len(raw), dtype="float64")\n    fine_count = np.zeros(len(raw), dtype="float64")\n\n    boundary_hit_count = np.zeros(len(raw), dtype="float64")\n    outside_count = np.zeros(len(raw), dtype="float64")\n    pressure_sum = np.zeros(len(raw), dtype="float64")\n    pressure_max = np.zeros(len(raw), dtype="float64")\n\n    for column in NUMERIC_COLUMNS:\n        series = _as_numeric_series(raw, column)\n        finite = series.notna().to_numpy()\n        observed_count += finite.astype("float64")\n\n        if column == "sleep_duration":\n            coarse = _is_multiple(series, 0.5).to_numpy()\n            features[column + "_whole_hour_heap"] = _is_multiple(series, 1.0).astype("int8")\n            features[column + "_half_hour_heap"] = coarse.astype("int8")\n        elif column == "heart_rate":\n            coarse = _is_multiple(series, 5.0).to_numpy()\n            features[column + "_multiple_5_heap"] = coarse.astype("int8")\n            features[column + "_multiple_10_heap"] = _is_multiple(series, 10.0).astype("int8")\n        elif column == "bmi":\n            coarse = _is_multiple(series, 0.5).to_numpy()\n            features[column + "_whole_heap"] = _is_multiple(series, 1.0).astype("int8")\n            features[column + "_half_heap"] = coarse.astype("int8")\n            features[column + "_one_decimal_heap"] = _is_multiple(series, 0.1).astype("int8")\n        elif column == "calorie_expenditure":\n            coarse = _is_multiple(series, 50.0).to_numpy()\n            features[column + "_multiple_50_heap"] = coarse.astype("int8")\n            features[column + "_multiple_100_heap"] = _is_multiple(series, 100.0).astype("int8")\n        elif column == "step_count":\n            coarse = _is_multiple(series, 500.0).to_numpy()\n            features[column + "_multiple_500_heap"] = coarse.astype("int8")\n            features[column + "_multiple_1000_heap"] = _is_multiple(series, 1000.0).astype("int8")\n        elif column == "exercise_duration":\n            coarse = _is_multiple(series, 5.0).to_numpy()\n            features[column + "_multiple_5_heap"] = coarse.astype("int8")\n            features[column + "_multiple_10_heap"] = _is_multiple(series, 10.0).astype("int8")\n            features[column + "_multiple_30_heap"] = _is_multiple(series, 30.0).astype("int8")\n        else:\n            coarse = _is_multiple(series, 0.25).to_numpy()\n            features[column + "_quarter_liter_heap"] = coarse.astype("int8")\n            features[column + "_half_liter_heap"] = _is_multiple(series, 0.5).astype("int8")\n\n        coarse_count += (coarse & finite).astype("float64")\n\n        integer_tier, one_decimal_tier, two_decimal_tier, finer_tier, finite_tier = _decimal_tiers(series)\n        features[column + "_precision_integer"] = integer_tier.astype("int8")\n        features[column + "_precision_one_decimal"] = one_decimal_tier.astype("int8")\n        features[column + "_precision_two_decimal"] = two_decimal_tier.astype("int8")\n        features[column + "_precision_finer"] = finer_tier.astype("int8")\n\n        integer_count += integer_tier.astype("float64")\n        tenth_count += one_decimal_tier.astype("float64")\n        hundredth_count += two_decimal_tier.astype("float64")\n        fine_count += finer_tier.astype("float64")\n\n        train_values = series.loc[train_mask & series.notna()]\n        if train_values.empty:\n            lower = np.nan\n            upper = np.nan\n            iqr = np.nan\n        else:\n            lower = float(train_values.min())\n            upper = float(train_values.max())\n            q1 = float(train_values.quantile(0.25))\n            q3 = float(train_values.quantile(0.75))\n            iqr = q3 - q1\n\n        values = series.to_numpy(dtype="float64", copy=False)\n        if np.isfinite(lower) and np.isfinite(upper):\n            train_range = upper - lower\n            scale = max(0.02 * train_range, 0.05 * iqr if np.isfinite(iqr) else 0.0, EPSILON)\n            lower_hit = finite & (np.abs(values - lower) <= EPSILON)\n            upper_hit = finite & (np.abs(values - upper) <= EPSILON)\n            outside = finite & ((values < lower) | (values > upper))\n            distance_to_bound = np.minimum(np.abs(values - lower), np.abs(values - upper))\n            pressure = np.clip(1.0 - distance_to_bound / scale, 0.0, 1.0)\n            pressure = np.where(finite, pressure, 0.0)\n            pressure = np.where(outside, 1.0, pressure)\n        else:\n            lower_hit = np.zeros(len(raw), dtype=bool)\n            upper_hit = np.zeros(len(raw), dtype=bool)\n            outside = np.zeros(len(raw), dtype=bool)\n            pressure = np.zeros(len(raw), dtype="float64")\n\n        features[column + "_train_lower_bound_hit"] = lower_hit.astype("int8")\n        features[column + "_train_upper_bound_hit"] = upper_hit.astype("int8")\n        features[column + "_outside_train_envelope"] = outside.astype("int8")\n        features[column + "_boundary_pressure"] = pressure.astype("float32")\n\n        boundary_hit_count += (lower_hit | upper_hit).astype("float64")\n        outside_count += outside.astype("float64")\n        pressure_sum += pressure\n        pressure_max = np.maximum(pressure_max, pressure)\n\n    features["observed_numeric_count"] = observed_count.astype("float32")\n    features["coarse_heaped_fraction"] = _safe_fraction(coarse_count, observed_count).astype("float32")\n    features["integer_like_fraction"] = _safe_fraction(integer_count, observed_count).astype("float32")\n    features["tenth_like_fraction"] = _safe_fraction(tenth_count, observed_count).astype("float32")\n    features["hundredth_like_fraction"] = _safe_fraction(hundredth_count, observed_count).astype("float32")\n    features["fine_grained_fraction"] = _safe_fraction(fine_count, observed_count).astype("float32")\n    features["boundary_hit_count"] = boundary_hit_count.astype("float32")\n    features["outside_train_envelope_count"] = outside_count.astype("float32")\n    features["max_boundary_pressure"] = pressure_max.astype("float32")\n    features["mean_boundary_pressure"] = _safe_fraction(pressure_sum, observed_count).astype("float32")\n\n    return features\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "report_granularity_clipping_signature",\n        "fn": add_report_granularity_clipping_signature,\n        "depends_on": [],\n        "description": "Measurement granularity, heaping, and train-boundary clipping signatures for raw student health measurements.",\n    }\n]'

HYPOTHESIS_000017_AUTOGLUON_001_PY_E5A9FDFA20_SOURCE = 'import numpy as np\nimport pandas as pd\n\n\n_STEP_SUPPORT_BINS = (-np.inf, 5000.0, 7500.0, 10000.0, 12500.0, np.inf)\n_STEP_SUPPORT_VALUES = (-2.0, -1.0, 0.0, 1.0, 2.0)\n\n_EXERCISE_SUPPORT_BINS = (-np.inf, 0.0, 15.0, 30.0, np.inf)\n_EXERCISE_SUPPORT_VALUES = (-1.0, 0.0, 1.0, 2.0)\n\n_ACTIVITY_LEVEL_MAP = {\n    "sedentary": -1.0,\n    "moderate": 0.0,\n    "active": 1.0,\n}\n\n\ndef _numeric_series(raw, column_name):\n    if column_name in raw.columns:\n        return pd.to_numeric(raw[column_name], errors="coerce")\n    return pd.Series(np.nan, index=raw.index, dtype="float64")\n\n\ndef _string_series(raw, column_name):\n    if column_name in raw.columns:\n        return raw[column_name].astype("string").str.lower()\n    return pd.Series(pd.NA, index=raw.index, dtype="string")\n\n\ndef add_weight_status_activity_buffer(raw, deps, aux):\n    bmi = _numeric_series(raw, "bmi")\n    step_count = _numeric_series(raw, "step_count")\n    exercise_duration = _numeric_series(raw, "exercise_duration")\n    activity_level = _string_series(raw, "physical_activity_level")\n\n    out = pd.DataFrame(index=raw.index)\n\n    bmi_zone_ordinal = pd.Series(0, index=raw.index, dtype="int8")\n    bmi_zone_ordinal = bmi_zone_ordinal.mask(bmi < 18.5, 1)\n    bmi_zone_ordinal = bmi_zone_ordinal.mask((bmi >= 18.5) & (bmi < 25.0), 2)\n    bmi_zone_ordinal = bmi_zone_ordinal.mask((bmi >= 25.0) & (bmi < 30.0), 3)\n    bmi_zone_ordinal = bmi_zone_ordinal.mask(bmi >= 30.0, 4)\n\n    bmi_zone_label = pd.Series("unknown", index=raw.index, dtype="object")\n    bmi_zone_label = bmi_zone_label.mask(bmi_zone_ordinal == 1, "underweight")\n    bmi_zone_label = bmi_zone_label.mask(bmi_zone_ordinal == 2, "healthy")\n    bmi_zone_label = bmi_zone_label.mask(bmi_zone_ordinal == 3, "overweight")\n    bmi_zone_label = bmi_zone_label.mask(bmi_zone_ordinal == 4, "obesity")\n\n    below_healthy = ((18.5 - bmi) / 5.0).clip(lower=0.0, upper=2.0)\n    above_healthy = ((bmi - 25.0) / 5.0).clip(lower=0.0, upper=2.0)\n    body_mass_severity = pd.concat([below_healthy, above_healthy], axis=1).max(axis=1)\n    body_mass_severity = body_mass_severity.where(bmi.notna(), np.nan)\n\n    step_support = pd.Series(np.nan, index=raw.index, dtype="float64")\n    for lower, upper, value in zip(_STEP_SUPPORT_BINS[:-1], _STEP_SUPPORT_BINS[1:], _STEP_SUPPORT_VALUES):\n        step_support = step_support.mask((step_count >= lower) & (step_count < upper), value)\n\n    exercise_support = pd.Series(np.nan, index=raw.index, dtype="float64")\n    exercise_known = exercise_duration.notna()\n    exercise_support = exercise_support.mask(exercise_known & (exercise_duration <= 0.0), -1.0)\n    exercise_support = exercise_support.mask(exercise_known & (exercise_duration > 0.0) & (exercise_duration < 15.0), 0.0)\n    exercise_support = exercise_support.mask(exercise_known & (exercise_duration >= 15.0) & (exercise_duration < 30.0), 1.0)\n    exercise_support = exercise_support.mask(exercise_known & (exercise_duration >= 30.0), 2.0)\n\n    level_support = activity_level.map(_ACTIVITY_LEVEL_MAP).astype("float64")\n\n    support_components = pd.concat(\n        [step_support, exercise_support, level_support],\n        axis=1,\n    )\n    activity_support_score = support_components.mean(axis=1, skipna=True)\n    activity_known_count = support_components.notna().sum(axis=1).astype("int8")\n\n    activity_support_state = pd.Series("unknown", index=raw.index, dtype="object")\n    activity_support_state = activity_support_state.mask(activity_known_count.gt(0) & (activity_support_score < -0.5), "low")\n    activity_support_state = activity_support_state.mask(\n        activity_known_count.gt(0) & (activity_support_score >= -0.5) & (activity_support_score <= 0.5),\n        "neutral",\n    )\n    activity_support_state = activity_support_state.mask(activity_known_count.gt(0) & (activity_support_score > 0.5), "high")\n\n    sedentary_side = (-activity_support_score).clip(lower=0.0, upper=2.0).where(activity_known_count.gt(0), np.nan)\n    active_side = activity_support_score.clip(lower=0.0, upper=2.0).where(activity_known_count.gt(0), np.nan)\n    healthy_bmi_flag = (bmi_zone_ordinal == 2).astype("int8")\n    nonhealthy_bmi_flag = bmi.notna() & (bmi_zone_ordinal != 2)\n\n    out["bmi_zone_ordinal"] = bmi_zone_ordinal\n    out["bmi_nonhealthy_flag"] = nonhealthy_bmi_flag.astype("int8")\n    out["bmi_nonhealthy_severity"] = body_mass_severity.astype("float32")\n    out["activity_support_score"] = activity_support_score.astype("float32")\n    out["activity_support_state"] = activity_support_state\n    out["activity_support_observed_count"] = activity_known_count\n    out["amplified_weight_risk"] = (body_mass_severity * sedentary_side).astype("float32")\n    out["buffered_weight_risk"] = (body_mass_severity * active_side).astype("float32")\n    out["healthy_weight_inactivity"] = (healthy_bmi_flag * sedentary_side).astype("float32")\n    out["bmi_activity_cross"] = (bmi_zone_label.astype("string") + "__" + activity_support_state.astype("string")).astype("object")\n\n    return out\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "weight_status_activity_buffer",\n        "fn": add_weight_status_activity_buffer,\n        "depends_on": [],\n        "description": "Contextual BMI status features that distinguish activity-buffered weight risk from activity-amplified weight risk.",\n    }\n]'

HYPOTHESIS_000031_AUTOGLUON_001_PY_0806C29E0F_SOURCE = 'import numpy as np\nimport pandas as pd\n\n\nGROUP_NAME = "gender_lifestyle_category_typicality"\nGENDER_COL = "gender"\nID_COL = "id"\nTRAIN_ID_UPPER_EXCLUSIVE = 690088\nMISSING_TOKEN = "__missing__"\nUNKNOWN_TOKEN = "__unknown__"\nALPHA = 1.0\nLOW_PROB_THRESHOLD = 0.20\n\nLIFESTYLE_COLS = (\n    "diet_type",\n    "stress_level",\n    "sleep_quality",\n    "physical_activity_level",\n    "smoking_alcohol",\n)\n\n\ndef _as_token_series(df, col):\n    if col not in df.columns:\n        return pd.Series(MISSING_TOKEN, index=df.index, dtype="object")\n    values = df[col].astype("object").where(df[col].notna(), MISSING_TOKEN)\n    return values.astype(str)\n\n\ndef _fit_mask(raw):\n    if ID_COL not in raw.columns:\n        return pd.Series(True, index=raw.index)\n\n    ids = pd.to_numeric(raw[ID_COL], errors="coerce")\n    mask = ids.lt(TRAIN_ID_UPPER_EXCLUSIVE)\n    if bool(mask.any()):\n        return mask.fillna(False)\n    return pd.Series(True, index=raw.index)\n\n\ndef add_gender_lifestyle_category_typicality(raw, deps, aux):\n    fit_mask = _fit_mask(raw)\n\n    gender_all = _as_token_series(raw, GENDER_COL)\n    gender_fit = gender_all.loc[fit_mask]\n\n    out = pd.DataFrame(index=raw.index)\n\n    cond_surprises = []\n    overall_surprises = []\n    log_lifts = []\n    cond_log_probs = []\n    low_prob_flags = []\n\n    n_fit = int(fit_mask.sum())\n\n    for col in LIFESTYLE_COLS:\n        value_all = _as_token_series(raw, col)\n        value_fit = value_all.loc[fit_mask]\n\n        levels = pd.Index(value_fit.unique()).union(pd.Index([MISSING_TOKEN]))\n        genders = pd.Index(gender_fit.unique()).union(pd.Index([MISSING_TOKEN]))\n\n        n_levels = int(len(levels))\n        n_genders = int(len(genders))\n\n        overall_counts = value_fit.value_counts(dropna=False)\n        overall_denom = float(n_fit + ALPHA * n_levels)\n        overall_probs = (overall_counts.reindex(levels, fill_value=0).astype(float) + ALPHA) / overall_denom\n        default_overall_prob = float(ALPHA / overall_denom)\n\n        pair_counts = pd.crosstab(gender_fit, value_fit, dropna=False)\n        pair_counts = pair_counts.reindex(index=genders, columns=levels, fill_value=0).astype(float)\n        gender_counts = gender_fit.value_counts(dropna=False).reindex(genders, fill_value=0).astype(float)\n        cond_probs = pair_counts.add(ALPHA).div(gender_counts.add(ALPHA * n_levels), axis=0)\n\n        row_index = pd.MultiIndex.from_arrays([gender_all, value_all])\n        cond_lookup = cond_probs.stack(dropna=False)\n        cond_prob = pd.Series(row_index.map(cond_lookup), index=raw.index, dtype="float64")\n\n        overall_prob = value_all.map(overall_probs).astype("float64").fillna(default_overall_prob)\n        cond_prob = cond_prob.fillna(overall_prob)\n\n        cond_prob = cond_prob.clip(lower=np.finfo(float).tiny)\n        overall_prob = overall_prob.clip(lower=np.finfo(float).tiny)\n\n        cond_surprise = -np.log(cond_prob)\n        overall_surprise = -np.log(overall_prob)\n        log_lift = np.log(cond_prob) - np.log(overall_prob)\n\n        cond_surprises.append(cond_surprise)\n        overall_surprises.append(overall_surprise)\n        log_lifts.append(log_lift)\n        cond_log_probs.append(np.log(cond_prob))\n        low_prob_flags.append(cond_prob.lt(LOW_PROB_THRESHOLD).astype("int8"))\n\n    cond_surprise_df = pd.concat(cond_surprises, axis=1)\n    overall_surprise_df = pd.concat(overall_surprises, axis=1)\n    log_lift_df = pd.concat(log_lifts, axis=1)\n    cond_log_prob_df = pd.concat(cond_log_probs, axis=1)\n    low_prob_df = pd.concat(low_prob_flags, axis=1)\n\n    out["mean_conditional_surprise"] = cond_surprise_df.mean(axis=1)\n    out["max_conditional_surprise"] = cond_surprise_df.max(axis=1)\n    out["sum_conditional_surprise"] = cond_surprise_df.sum(axis=1)\n    out["sum_overall_surprise"] = overall_surprise_df.sum(axis=1)\n    out["low_gender_probability_count"] = low_prob_df.sum(axis=1).astype("int8")\n    out["mean_gender_log_lift"] = log_lift_df.mean(axis=1)\n    out["sum_abs_gender_log_lift"] = log_lift_df.abs().sum(axis=1)\n    out["summed_conditional_log_probability"] = cond_log_prob_df.sum(axis=1)\n\n    return out\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "gender_lifestyle_category_typicality",\n        "fn": add_gender_lifestyle_category_typicality,\n        "depends_on": [],\n        "description": "Smoothed same-gender typicality aggregates for lifestyle category values.",\n    }\n]'

